// Generates src/data/br-municipalities.geo.ts from IBGE's national municipality mesh.
//
// Run manually; the output is committed (mirrors how br-states.geo.ts is a bundled,
// pre-simplified IBGE mesh). The frontend lazy-imports the generated file only when the
// "show municipalities" toggle is first enabled, so it lives in its own Vite chunk.
//
//   node scripts/build-municipalities-geo.mjs
//
// IBGE returns all 5,570 municipalities in one call, each tagged with `codarea` (the
// 7-digit IBGE code whose first two digits are the parent UF code). We keep only the
// code + geometry, round coordinates to 3 decimals (~110m — polygon count dominates the
// payload, so coarser rounding barely helps and degrades small municipalities), and emit a
// JSON string literal (fastest to parse, cheap for tsc).
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const URL =
  "https://servicodados.ibge.gov.br/api/v3/malhas/paises/BR" +
  "?formato=application/vnd.geo+json&intrarregiao=municipio&qualidade=minima";

const DECIMALS = 3;
const round = (n) => Math.round(n * 10 ** DECIMALS) / 10 ** DECIMALS;

function roundGeometry(geom) {
  const ring = (r) => r.map(([lon, lat]) => [round(lon), round(lat)]);
  if (geom.type === "Polygon") {
    return { type: "Polygon", coordinates: geom.coordinates.map(ring) };
  }
  return { type: "MultiPolygon", coordinates: geom.coordinates.map((poly) => poly.map(ring)) };
}

async function main() {
  console.log("Fetching IBGE municipality mesh…");
  const res = await fetch(URL, { headers: { Accept: "application/vnd.geo+json" } });
  if (!res.ok) throw new Error(`IBGE returned HTTP ${res.status}`);
  const gj = await res.json();
  const features = gj.features.map((f) => ({
    code: f.properties.codarea,
    geometry: roundGeometry(f.geometry),
  }));
  console.log(`Got ${features.length} municipalities.`);

  const json = JSON.stringify({ features });
  const banner =
    "// AUTO-GENERATED by scripts/build-municipalities-geo.mjs — do not edit by hand.\n" +
    "// Real IBGE municipality borders for all of Brazil (simplified, 3-decimal precision).\n" +
    "// Lazy-imported by src/data/municipalities.ts (its own Vite chunk).\n" +
    "import type { MunicipalitiesGeo } from \"./types\";\n\n";
  // JSON.parse of a string literal: fastest engine parse, and tsc treats it as a string.
  const body = `const data = JSON.parse(${JSON.stringify(json)}) as MunicipalitiesGeo;\nexport default data;\n`;

  const out = resolve(dirname(fileURLToPath(import.meta.url)), "../src/data/br-municipalities.geo.ts");
  writeFileSync(out, banner + body);
  console.log(`Wrote ${out} (${(Buffer.byteLength(banner + body) / 1e6).toFixed(2)} MB).`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
